/**
 * @summary List AI interaction logs for a clinic
 */
export const getListAiLogsUrl = (
  clinicId: number,
  params?: ListAiLogsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/clinics/${clinicId}/ai-logs?${stringifiedParams}`
    : `/api/clinics/${clinicId}/ai-logs`;
};

export const listAiLogs = async (
  clinicId: number,
  params?: ListAiLogsParams,
  options?: RequestInit,
): Promise<AiLog[]> => {
  return customFetch<AiLog[]>(getListAiLogsUrl(clinicId, params), {
    ...options,
    method: "GET",
  });
};

export const getListAiLogsQueryKey = (
  clinicId: number,
  params?: ListAiLogsParams,
) => {
  return [
    `/api/clinics/${clinicId}/ai-logs`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListAiLogsQueryOptions = <
  TData = Awaited<ReturnType<typeof listAiLogs>>,
  TError = ErrorType<unknown>,
>(
  clinicId: number,
  params?: ListAiLogsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listAiLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListAiLogsQueryKey(clinicId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listAiLogs>>> = ({
    signal,
  }) => listAiLogs(clinicId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!clinicId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listAiLogs>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListAiLogsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listAiLogs>>
>;
export type ListAiLogsQueryError = ErrorType<unknown>;

/**
 * @summary List AI interaction logs for a clinic
 */

export function useListAiLogs<
  TData = Awaited<ReturnType<typeof listAiLogs>>,
  TError = ErrorType<unknown>,
>(
  clinicId: number,
  params?: ListAiLogsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listAiLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListAiLogsQueryOptions(clinicId, params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

